    white_active_moves = count_active_moves(board, 'white')
    black_active_moves = count_active_moves(board, 'black')

    # Calculate the overall evaluation
    eval_score = white_score - black_score + (white_squares_controlled - black_squares_controlled) + (white_active_moves - black_active_moves)

    # Determine the side with the advantage
