def parse_position(position):
    # Parse the input position into a 2D array
    board = [list(row) for row in position.split('/')]
    for i in range(8):
        row = board[i]
        new_row = []
        for square in row:
            if square.isdigit():
                new_row.extend(['.' for _ in range(int(square))])
            else:
                new_row.append(square)
        board[i] = new_row
    return np.array(board)

def get_piece_value(piece):
    # Return the value of a piece
    values = {'P': 1, 'N': 3, 'B': 3, 'R': 5, 'Q': 9}
    return values.get(piece, 0)

def count_controlled_squares(board, color):
    # Count the number of squares controlled by a color
    count = 0
    for i in range(8):
        for j in range(8):
            if is_square_controlled(board, i, j, color):
                count += 1
    return count

